mapper.select:
SELECT * FROM ( SELECT T0.*, ROWNUM RNUM FROM (
SELECT A.INDVDL_INFO_POLICY_ID AS "indvdlInfoId", A.INDVDL_INFO_POLICY_NM AS "indvdlInfoNm", A.INDVDL_INFO_POLICY_CN AS "indvdlInfoDc", A.INDVDL_INFO_POLICY_AGRE_AT AS "indvdlInfoYn", A.FRST_REGISTER_ID AS "frstRegisterId", TO_CHAR(A.FRST_REGIST_PNTTM,'YYYY-MM-DD') AS "frstRegistPnttm", A.VER AS "ver", A.APLC_DE AS "aplcDe", A.REPRSNT_AT AS "reprsntAt", (SELECT MBER_NM FROM TB_GNRL_MBER WHERE ESNTL_ID = A.FRST_REGISTER_ID) AS "frstRegisterNm" FROM TB_INDVDL_INFO_POLICY A WHERE 1=1
AND INDVDL_INFO_POLICY_NM LIKE '%' || #{searchKeyword} || '%'
AND INDVDL_INFO_POLICY_CN LIKE '%' || #{searchKeyword} || '%'
ORDER BY A.FRST_REGIST_PNTTM DESC
) T0 ) Z WHERE RNUM BETWEEN #{firstIndex} + 1 AND #{firstIndex} + #{recordCountPerPage}
